function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: Map<number, { to: number; start: number; end: number }[]> = new Map();
    for (const [u, v, s, e] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u)!.push({ to: v, start: s, end: e });
    }

    // Dijkstra's algorithm to find the minimum time to reach node n-1
    // Use a priority queue (min-heap) to process nodes by earliest arrival time
    const pq: [number, number][] = [[0, 0]]; // [time, node]
    const dist: Map<number, number> = new Map();
    dist.set(0, 0); // time to reach node 0 is 0

    while (pq.length > 0) {
        // Get the node with the earliest arrival time
        const [time, node] = pq.shift!();
        if (node === n - 1) {
            return time;
        }

        // Skip if we have already found a better time to reach this node
        if (dist.has(node) && dist.get(node)! < time) {
            continue;
        }

        // Explore all outgoing edges from this node
        if (adj.has(node)) {
            for (const edge of adj.get(node)!) {
                const { to, start, end } = edge;
                // Check if we can use this edge at the current time
                if (time >= start && time <= end) {
                    // We can take this edge, so move to the next node at time + 1
                    const newTime = time + 1;
                    if (!dist.has(to) || newTime < dist.get(to)!) {
                        dist.set(to, newTime);
                        pq.push([newTime, to]);
                    }
                } else {
                    // If the edge is not available at current time, we can wait
                    // Wait until the edge becomes available
                    const waitTime = Math.max(start, time + 1);
                    if (waitTime <= end) {
                        // Use the edge after waiting
                        const newTime = waitTime;
                        if (!dist.has(to) || newTime < dist.get(to)!) {
                            dist.set(to, newTime);
                            pq.push([newTime, to]);
                        }
                    }
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

